css:
body {
  background-color: #FFF5F5 !important;
  background-image:
    repeating-linear-gradient(
      135deg,
      rgba(196, 30, 58, 0.06),
      rgba(196, 30, 58, 0.06) 20px,
      #FFFFFF 20px,
      #FFFFFF 40px
    ) !important;
  background-attachment: fixed !important;
}
.album-row:nth-child(odd) {
  background: color-mix(in srgb, #FFFFFF var(--ts-row-surface-opacity, var(--ts-opacity-row)), transparent) !important;
  border-color: color-mix(in srgb, #F0C0C8 var(--ts-row-surface-opacity, var(--ts-opacity-row)), transparent) !important;
}
.album-row:nth-child(even) {
  background: color-mix(in srgb, #FCDCE2 var(--ts-row-surface-opacity, var(--ts-opacity-row)), transparent) !important;
  border-color: color-mix(in srgb, #E8A0B0 var(--ts-row-surface-opacity, var(--ts-opacity-row)), transparent) !important;
}
.album-row:nth-child(odd):hover {
  background: color-mix(in srgb, #FFFFFF var(--ts-opacity-row), transparent) !important;
  border-color: color-mix(in srgb, #C41E3A var(--ts-opacity-row), transparent) !important;
  box-shadow: 0 0 0 2.5px rgba(196, 30, 58, 1.0) !important;
}
.album-row:nth-child(even):hover {
  background: color-mix(in srgb, #F5C0CC var(--ts-opacity-row), transparent) !important;
}
.album-row.album-row-header, .album-row.album-row-header:hover {
  background: color-mix(in srgb, #C41E3A var(--ts-row-surface-opacity, var(--ts-opacity-row-header-background)), transparent) !important;
  border-color: color-mix(in srgb, #A01830 var(--ts-row-surface-opacity, var(--ts-opacity-row-header-background)), transparent) !important;
  color: #FFFFFF !important;
  box-shadow: none !important;
}
.album-row.album-row-header .row-cell { color: #FFFFFF !important; }
.album-row.album-row-header .album-row-header-separator { color: #FFFFFF !important; }
.album-row.album-row-header .sort-indicator { color: #FFFFFF !important; }
.header {
  background: color-mix(in srgb, #C41E3A var(--ts-opacity-header), transparent) !important;
  border-bottom: 2px solid color-mix(in srgb, #A01830 var(--ts-opacity-header), transparent) !important;
  color: #FFFFFF;
}
.header input, .header select { color: #3B0A14 !important; }
.header-title, .header .search-input::placeholder { color: #FFFFFF !important; }
.header-tooltip { background: #FFFFFF !important; }
.header-tooltip::after { border-right-color: #FFFFFF !important; }
.sidebar {
  background: #FFFFFF !important;
  border-right: 2px solid #F0C0C8 !important;
}
.album-card {
  border: 1.5px solid color-mix(in srgb, #F0C0C8 var(--ts-opacity-card), transparent) !important;
  border-radius: 12px !important;
}
.album-card:hover {
  border-color: color-mix(in srgb, #C41E3A var(--ts-opacity-card), transparent) !important;
  box-shadow: 0 4px 16px rgba(196, 30, 58, 0.15);
}
.modal {
  border: 2px solid #E8A0B0 !important;
  border-radius: 14px !important;
}
a, .artist-link { color: #C41E3A !important; }
a:hover, .artist-link:hover { color: #E02848 !important; }
::selection { background: #C41E3A; color: #FFFFFF; }
